<h4 class="settings-section-title">Security</h4>
<p class="settings-section-desc">Manage your password, two-factor authentication, and active sessions.</p>

<!-- Change Password -->
<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center" style="cursor:pointer;" @onclick="() => _passwordExpanded = !_passwordExpanded">
        <strong>Change Password</strong>
        <span>@(_passwordExpanded ? "▲" : "▼")</span>
    </div>
    @if (_passwordExpanded)
    {
        <div class="card-body">
