                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3" style="max-width: 400px;">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3" style="max-width: 400px;">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            @if (_passwordError is not null)
            {
                <div class="text-danger small mb-2">@_passwordError</div>
            }
            <button class="btn btn-primary" @onclick="HandleChangePassword">Update Password</button>

            @if (Settings.LastPasswordChange.HasValue)
            {
                <div class="text-muted small mt-2">
                    Last changed: @Settings.LastPasswordChange.Value.ToString("MMM dd, yyyy 'at' h:mm tt")
                </div>
            }
        </div>
    }
</div>

<!-- Two-Factor Authentication -->
<div class="card mb-4">
    <div class="card-body d-flex justify-content-between align-items-center">
        <div>
            <strong>Two-Factor Authentication</strong>
            <div class="mt-1">
                @if (_twoFactorEnabled)
                {
                    <span class="badge bg-success">Enabled</span>
                }
                else
                {
                    <span class="badge bg-secondary">Disabled</span>
                }
            </div>
        </div>
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" style="transform: scale(1.3);"
                   checked="@_twoFactorEnabled"
                   @onchange="(e) => _twoFactorEnabled = (bool)e.Value!" />
        </div>
    </div>
</div>

<!-- Active Sessions -->
<h6 class="fw-semibold mb-3">Active Sessions</h6>
<div class="table-responsive">
    <table class="table table-hover align-middle">
        <thead class="table-light">
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th class="text-end">Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Settings.Sessions)
            {
                var isCurrent = session == Settings.Sessions.FirstOrDefault();
                <tr>
                    <td>
                        @session.Device
                        @if (isCurrent)
                        {
                            <span class="badge bg-primary ms-1">Current</span>
                        }
                    </td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td class="text-end">
                        @if (!isCurrent)
                        {
                            @if (_confirmRevokeId == session.Id)
                            {
                                <span class="me-2 small text-danger">Are you sure?</span>
                                <button class="btn btn-danger btn-sm me-1" @onclick="() => ConfirmRevoke(session.Id)">Yes, Revoke</button>
                                <button class="btn btn-outline-secondary btn-sm" @onclick="() => _confirmRevokeId = null">Cancel</button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => _confirmRevokeId = session.Id">Revoke</button>
                            }
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter, EditorRequired] public required SecuritySettings Settings { get; set; }
    [Parameter, EditorRequired] public required EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public required EventCallback<string> OnRevokeSession { get; set; }

    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _twoFactorEnabled;
    private string? _confirmRevokeId;

    protected override void OnParametersSet()
    {
        _twoFactorEnabled = Settings.TwoFactorEnabled;
    }

    private async Task HandleChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }

        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordExpanded = false;
    }

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmRevokeId = null;
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

