        </label>
    </div>
</div>

<h6 class="fw-semibold">Muted Channels</h6>
<p class="text-muted small">Uncheck channels you want to receive notifications from.</p>

<div class="mb-4">
    @foreach (var channel in _allChannels)
    {
        var isMuted = _mutedChannels.Contains(channel);
        <div class="form-check mb-2">
            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                   checked="@isMuted"
                   @onchange="(e) => ToggleMute(channel, (bool)e.Value!)" />
            <label class="form-check-label text-capitalize" for="@($"ch-{channel}")">@channel</label>
        </div>
    }
</div>

<hr />

<button class="btn btn-primary" @onclick="HandleSave">Save Preferences</button>

@code {
    [Parameter, EditorRequired] public required NotificationPrefs Prefs { get; set; }
    [Parameter, EditorRequired] public required EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private readonly string[] _allChannels = ["announcements", "marketing", "social", "updates"];

    protected override void OnParametersSet()
    {
        _emailNotifications = Prefs.EmailNotifications;
        _pushNotifications = Prefs.PushNotifications;
        _weeklyDigest = Prefs.WeeklyDigest;
        _mutedChannels = [.. Prefs.MutedChannels];
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task HandleSave()
    {
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await OnSave.InvokeAsync(updated);
    }
}
