@page "/settings"
@rendermode InteractiveServer
@using sv_54e0ad71b1c74912a1a5abf1a9ab2777.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="px-3 py-2 mb-0 text-muted text-uppercase fw-semibold" style="font-size: 0.75rem; letter-spacing: 0.05em;">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link settings-nav-link @(section == _activeSection ? "active" : "")"
                            @onclick="() => SetActiveSection(section)">
                        <span class="settings-nav-icon">@GetIcon(section)</span>
                        @section
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="_profile!" OnSave="SaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="_notificationPrefs!" OnSave="SaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Settings="_securitySettings!"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="_appearanceSettings!" OnSave="SaveAppearance" />
                    break;
            }
        }

        @if (_toastMessage is not null)
        {
            <div class="settings-toast @(_toastIsError ? "settings-toast-error" : "")">
                @_toastMessage
            </div>
        }
    </div>
</div>

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionDataAsync();
    }

    private async Task LoadSectionDataAsync()
    {
        _loading = true;
        switch (_activeSection)
        {
            case "Profile":
                _profile = await SettingsService.GetProfileAsync();
                break;
            case "Notifications":
                _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                break;
            case "Security":
                _securitySettings = await SettingsService.GetSecuritySettingsAsync();
                break;
            case "Appearance":
                _appearanceSettings = await SettingsService.GetAppearanceAsync();
                break;
        }
        _loading = false;
    }

    private async Task SetActiveSection(string section)
    {
        if (section == _activeSection) return;
        _activeSection = section;
        await LoadSectionDataAsync();
    }

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
        await ShowToast("Profile saved successfully.");
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
        await ShowToast("Notification preferences saved.");
    }

    private async Task ChangePassword((string Current, string New) pw)
    {
        try
        {
            await SettingsService.ChangePasswordAsync(pw.Current, pw.New);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            await ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            await ShowToast(ex.Message, isError: true);
        }
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Session revoked.");
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearanceSettings = settings;
        await ShowToast("Appearance settings saved.");
    }

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
