toolArgs.file_text:
@using sv_54e0ad71b1c74912a1a5abf1a9ab2777.Services

<h4 class="settings-section-title">Profile</h4>
<p class="settings-section-desc">Manage your public profile information.</p>

<div class="row g-4">
    <div class="col-md-8">
        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>
        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>
        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="4" @bind="_bio"></textarea>
        </div>
    </div>
    <div class="col-md-4 text-center">
        <label class="form-label fw-semibold d-block">Avatar</label>
        <div class="avatar-preview mb-2">
            @if (!string.IsNullOrWhiteSpace(_avatarUrl))
            {
                <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" style="width:100px;height:100px;object-fit:cover;" />
            }
            else
            {
                <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center text-white"
                     style="width:100px;height:100px;margin:0 auto;font-size:2rem;">
                    👤
                </div>
            }
        </div>
        <div class="mb-3">
            <label class="form-label small text-muted">Avatar URL</label>
            <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
        </div>
    </div>
</div>

<hr />

<div class="d-flex gap-2">
    <button class="btn btn-primary" @onclick="HandleSave" disabled="@(!HasChanges)">
        Save Changes
    </button>
    <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@(!HasChanges)">
        Discard Changes
    </button>
</div>

@code {
    [Parameter, EditorRequired] public required UserProfile Profile { get; set; }
    [Parameter, EditorRequired] public required EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    protected override void OnParametersSet()
    {
        ResetFromProfile();
    }

    private void ResetFromProfile()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private bool HasChanges =>
        _displayName != Profile.DisplayName ||
        _email != Profile.Email ||
        _avatarUrl != Profile.AvatarUrl ||
        _bio != Profile.Bio;

    private async Task HandleSave()
    {
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await OnSave.InvokeAsync(updated);
    }

    private void DiscardChanges() => ResetFromProfile();
}

@using sv_54e0ad71b1c74912a1a5abf1a9ab2777.Services

<h4 class="settings-section-title">Notifications</h4>
<p class="settings-section-desc">Choose how and when you want to be notified.</p>

<div class="mb-4">
    <div class="form-check form-switch mb-3">
        <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
        <label class="form-check-label" for="emailNotif">
            <strong>Email Notifications</strong>
            <div class="text-muted small">Receive notifications via email</div>
        </label>
    </div>
    <div class="form-check form-switch mb-3">
        <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
        <label class="form-check-label" for="pushNotif">
            <strong>Push Notifications</strong>
            <div class="text-muted small">Receive browser push notifications</div>
        </label>
    </div>
    <div class="form-check form-switch mb-3">
        <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
        <label class="form-check-label" for="weeklyDigest">
            <strong>Weekly Digest</strong>
            <div class="text-muted small">Receive a weekly summary of activity</div>
        </label>
    </div>
</div>

<h6 class="fw-semibold">Muted Channels</h6>
<p class="text-muted small">Uncheck channels you want to receive notifications from.</p>

<div class="mb-4">
    @foreach (var channel in _allChannels)
    {
        var isMuted = _mutedChannels.Contains(channel);
        <div class="form-check mb-2">
            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                   checked="@isMuted"
                   @onchange="(e) => ToggleMute(channel, (bool)e.Value!)" />
            <label class="form-check-label text-capitalize" for="@($"ch-{channel}")">@channel</label>
        </div>
    }
</div>

<hr />

<button class="btn btn-primary" @onclick="HandleSave">Save Preferences</button>

@code {
    [Parameter, EditorRequired] public required NotificationPrefs Prefs { get; set; }
    [Parameter, EditorRequired] public required EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private readonly string[] _allChannels = ["announcements", "marketing", "social", "updates"];

    protected override void OnParametersSet()
    {
        _emailNotifications = Prefs.EmailNotifications;
        _pushNotifications = Prefs.PushNotifications;
        _weeklyDigest = Prefs.WeeklyDigest;
        _mutedChannels = [.. Prefs.MutedChannels];
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task HandleSave()
    {
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await OnSave.InvokeAsync(updated);
    }
}

@using sv_54e0ad71b1c74912a1a5abf1a9ab2777.Services

<h4 class="settings-section-title">Security</h4>
<p class="settings-section-desc">Manage your password, two-factor authentication, and active sessions.</p>

<!-- Change Password -->
<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center" style="cursor:pointer;" @onclick="() => _passwordExpanded = !_passwordExpanded">
        <strong>Change Password</strong>
        <span>@(_passwordExpanded ? "▲" : "▼")</span>
    </div>
    @if (_passwordExpanded)
    {
        <div class="card-body">
            <div class="mb-3" style="max-width: 400px;">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3" style="max-width: 400px;">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3" style="max-width: 400px;">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            @if (_passwordError is not null)
            {
                <div class="text-danger small mb-2">@_passwordError</div>
            }
            <button class="btn btn-primary" @onclick="HandleChangePassword">Update Password</button>

            @if (Settings.LastPasswordChange.HasValue)
            {
                <div class="text-muted small mt-2">
                    Last changed: @Settings.LastPasswordChange.Value.ToString("MMM dd, yyyy 'at' h:mm tt")
                </div>
            }
        </div>
    }
</div>

<!-- Two-Factor Authentication -->
<div class="card mb-4">
    <div class="card-body d-flex justify-content-between align-items-center">
        <div>
            <strong>Two-Factor Authentication</strong>
            <div class="mt-1">
                @if (_twoFactorEnabled)
                {
                    <span class="badge bg-success">Enabled</span>
                }
                else
                {
                    <span class="badge bg-secondary">Disabled</span>
                }
            </div>
        </div>
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" style="transform: scale(1.3);"
                   checked="@_twoFactorEnabled"
                   @onchange="(e) => _twoFactorEnabled = (bool)e.Value!" />
        </div>
    </div>
</div>

<!-- Active Sessions -->
<h6 class="fw-semibold mb-3">Active Sessions</h6>
<div class="table-responsive">
    <table class="table table-hover align-middle">
        <thead class="table-light">
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th class="text-end">Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Settings.Sessions)
            {
                var isCurrent = session == Settings.Sessions.FirstOrDefault();
                <tr>
                    <td>
                        @session.Device
                        @if (isCurrent)
                        {
                            <span class="badge bg-primary ms-1">Current</span>
                        }
                    </td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td class="text-end">
                        @if (!isCurrent)
                        {
                            @if (_confirmRevokeId == session.Id)
                            {
                                <span class="me-2 small text-danger">Are you sure?</span>
                                <button class="btn btn-danger btn-sm me-1" @onclick="() => ConfirmRevoke(session.Id)">Yes, Revoke</button>
                                <button class="btn btn-outline-secondary btn-sm" @onclick="() => _confirmRevokeId = null">Cancel</button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => _confirmRevokeId = session.Id">Revoke</button>
                            }
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter, EditorRequired] public required SecuritySettings Settings { get; set; }
    [Parameter, EditorRequired] public required EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public required EventCallback<string> OnRevokeSession { get; set; }

    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _twoFactorEnabled;
    private string? _confirmRevokeId;

    protected override void OnParametersSet()
    {
        _twoFactorEnabled = Settings.TwoFactorEnabled;
    }

    private async Task HandleChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }

        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordExpanded = false;
    }

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmRevokeId = null;
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

