@using sv_54e0ad71b1c74912a1a5abf1a9ab2777.Services

<h4 class="settings-section-title">Appearance</h4>
<p class="settings-section-desc">Customize how the application looks and feels.</p>

<div class="row g-4">
    <div class="col-md-7">
        <!-- Theme -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Theme</label>
            <div class="d-flex gap-3">
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>
        </div>

        <!-- Font Size -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Font Size</label>
            <div class="d-flex gap-3">
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>
        </div>

        <!-- Language -->
        <div class="mb-4" style="max-width: 300px;">
            <label class="form-label fw-semibold">Language</label>
            <select class="form-select" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">
                    <strong>Compact Mode</strong>
                    <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                </label>
            </div>
        </div>
    </div>

    <!-- Live Preview -->
    <div class="col-md-5">
        <label class="form-label fw-semibold">Preview</label>
        <div class="appearance-preview @GetPreviewClasses()" style="@GetPreviewStyles()">
            <div class="preview-header">
                <strong>Dashboard</strong>
            </div>
            <div class="preview-body">
                <div class="preview-card">
                    <div class="preview-card-title">Sample Card</div>
                    <div class="preview-card-text">This is how your content will look with the selected settings.</div>
                    <button class="preview-btn">Action</button>
                </div>
                <div class="preview-nav-item">📊 Analytics</div>
                <div class="preview-nav-item">📁 Projects</div>
                <div class="preview-nav-item">⚙️ Settings</div>
            </div>
        </div>
    </div>
</div>

<hr />

<button class="btn btn-primary" @onclick="HandleSave">Save</button>

@code {
    [Parameter, EditorRequired] public required AppearanceSettings Settings { get; set; }
    [Parameter, EditorRequired] public required EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese"];

    protected override void OnParametersSet()
    {
        _theme = Settings.Theme;
        _fontSize = Settings.FontSize;
        _language = Settings.Language;
        _compactMode = Settings.CompactMode;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_theme == "Dark") classes.Add("preview-dark");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private string GetPreviewStyles()
    {
        var size = _fontSize switch
        {
            "Small" => "12px",
            "Large" => "18px",
            _ => "14px"
        };
        return $"font-size: {size};";
    }

    private async Task HandleSave()
    {
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
    }
}

.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
    background: #fff;
    color: #212529;
}

.appearance-preview.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: #f8f9fa;
}

.preview-dark .preview-header {
    background: #313244;
    border-color: #45475a;
}

.preview-body {
    padding: 0.75rem 1rem;
}

.preview-compact .preview-header {
    padding: 0.35rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.35rem 0.75rem;
}

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
    margin-bottom: 0.75rem;
}

.preview-dark .preview-card {
    border-color: #45475a;
    background: #313244;
}

.preview-compact .preview-card {
    padding: 0.35rem 0.5rem;
    margin-bottom: 0.35rem;
}

.preview-card-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.preview-card-text {
    opacity: 0.75;
    margin-bottom: 0.5rem;
}

.preview-compact .preview-card-text {
    margin-bottom: 0.25rem;
}

.preview-btn {
    padding: 0.25rem 0.75rem;
    border: none;
    border-radius: 0.25rem;
    background: #0d6efd;
    color: #fff;
    font-size: inherit;
    cursor: default;
}

.preview-dark .preview-btn {
    background: #89b4fa;
    color: #1e1e2e;
}

.preview-nav-item {
    padding: 0.4rem 0.5rem;
    border-radius: 0.25rem;
    margin-bottom: 0.25rem;
}

.preview-compact .preview-nav-item {
    padding: 0.2rem 0.35rem;
    margin-bottom: 0.1rem;
}

.preview-nav-item:hover {
    background: rgba(0, 0, 0, 0.05);
}

.preview-dark .preview-nav-item:hover {
    background: rgba(255, 255, 255, 0.05);
}

